diff --git a/src/test/fuzz/process_message.cpp b/src/test/fuzz/process_message.cpp
index f5d5989..6bfcb7a 100644
--- a/src/test/fuzz/process_message.cpp
+++ b/src/test/fuzz/process_message.cpp
@@ -6,3 +6,5 @@
 #include <banman.h>
+#include <coins.h>
 #include <consensus/consensus.h>
+#include <core_io.h>
 #include <kernel/chainparams.h>
@@ -45,2 +47,3 @@ TestingSetup* g_setup;
 std::string_view LIMIT_TO_MESSAGE_TYPE{};
+std::vector<COutPoint> g_mature_coinbase_outpoints;

@@ -52,5 +55,10 @@ void ResetChainman(TestingSetup& setup)
     setup.LoadVerifyActivateChainstate();
+    g_mature_coinbase_outpoints.clear();
     for (int i = 0; i < 2 * COINBASE_MATURITY; i++) {
         node::BlockCreateOptions options;
-        MineBlock(setup.m_node, options);
+        options.coinbase_output_script = P2WSH_OP_TRUE;
+        const COutPoint coinbase_outpoint{MineBlock(setup.m_node, options)};
+        if (i < COINBASE_MATURITY) {
+            g_mature_coinbase_outpoints.push_back(coinbase_outpoint);
+        }
     }
@@ -89,2 +97,24 @@ FUZZ_TARGET(process_message, .init = initialize_process_message)

+    Assert(!g_mature_coinbase_outpoints.empty());
+
+    const COutPoint prevout{PickValue(fuzzed_data_provider, g_mature_coinbase_outpoints)};
+    CAmount coin_value;
+    {
+        LOCK(cs_main);
+        coin_value = node.chainman->ActiveChainstate().CoinsTip().AccessCoin(prevout).out.nValue;
+    }
+    Assert(coin_value > 1);
+    CMutableTransaction mtx;
+    mtx.vin.resize(1);
+    mtx.vin[0].prevout = prevout;
+    mtx.vin[0].scriptWitness.stack = {WITNESS_STACK_ELEM_OP_TRUE};
+    mtx.vout.emplace_back(coin_value - 1, P2WSH_OP_TRUE);
+    const CTransactionRef tx{MakeTransactionRef(mtx)};
+
+    LOCK(cs_main);
+    const auto tx_result{node.chainman->ProcessTransaction(tx)};
+    Assert(tx_result.m_result_type == MempoolAcceptResult::ResultType::VALID);
+    std::cout << EncodeHexTx(*tx) << std::endl;
+    Assert(node.mempool->size() == 0);
+
     // Reset, so that dangling pointers can be detected by sanitizers.
